VALUES
('bookkeeper-moex-01087', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '下列為新竹公司7月31日之資訊。帳列銀行存款餘額為$655,710，銀行結單之餘額則為$653,900。核對 後發現㉑7月31日送存之$15,300銀行尚未入帳，㉒銀行代收手續費$550公司尚未入帳，㉓公司開出之 支票尚有$14,130未兌現，㉔公司支付運費之支票$2,320公司帳上誤記為$2,230。試問，7月31日正確之 銀行存款餘額為：', '["$655,070", "$656,710", "$683,330", "$624,470"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01088', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '賒銷商品$200,000，付款條件3/10、2/20、n/30，10天內支付一半款項。其餘款項於第22天支付，共支 付多少現金？', '["$200,000", "$197,000", "$195,000", "$198,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01089', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '下列起運點交貨之敘述何者正確？', '["商品所有權於送達目的地時轉移予買方，運費由賣方負擔", "商品所有權於送達目的地時轉移予買方，運費由買方負擔", "商品所有權於起運時轉移予買方，運費由賣方負擔", "商品所有權於起運時轉移予買方，運費由買方負擔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01090', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司 X1 年初之存貨金額為$1,800，購貨相關之應付帳款金額為貸餘$1,500，X1 年底之存貨金額為 $1,700，購貨相關之應付帳款金額為貸餘$1,900，且X1年之銷貨成本金額為$5,000。該公司X1年支付予 存貨供應商之金額為：', '["$4,500", "$4,900", "$5,100", "$5,400"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01091', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '桃園公司X6年的原帳列稅前淨利為$350,000。會計師查核時發現期末存貨高估了$17,500，期初存貨低估 了$12,500。試問桃園公司X6年正確之稅前淨利為何？', '["$345,000", "$355,000", "$320,000", "$380,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01092', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '屏東公司 X5 年報導期間結束日應收帳款總額$970,000，並設定應收帳款總額的 6%為其期末備抵壞帳餘 額。X6 年中，實際沖銷壞帳$38,800。經評估，於 X6 年期末加提$34,500 為其應收帳款之備抵壞帳。試 問X6年底備抵壞帳之餘額為:', '["$53,900", "$58,200", "$38,800", "$19,400"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01093', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '高雄公司於X6年10月1日購入一部價值$1,500,000的機器，估計使用年限4年，預計總產量10,000,000 單位，估計殘值為$100,000，假設X6年共產出600,000單位。以直線法折舊，則X6年底之折舊費用為:', '["$90,000", "$58,333", "$60,000", "$87,500"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01094', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司於X1年初以$500,000購入乙公司30%股份分類為採用權益法之投資。乙公司X1年之本期淨利為 $100,000，其他綜合損益為損失$200,000，X1 年並發放現金股利$10,000。若甲公司對乙公司投資之原始 成本等於股權淨值，甲公司X1年該投資帳面金額之變動數為（不考慮所得稅影響）：', '["減少$33,000", "減少$30,000", "增加$27,000", "增加$30,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01095', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '基隆公司購置機器一部，定價$500,000。廠商提供現金折扣$55,000，支付運費$30,000，運送中因超速被 罰款$16,000。運抵廠房後另付安裝費$35,000，則該機器應有之帳面成本為：', '["$510,000", "$526,000", "$475,000", "$491,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01096', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '宜蘭公司於X6年3月1日發行面額$2,000,000，利率8%，市場利率為10%之3年期公司債，發行價格為 $1,898,485。利息於每年2月28日及8月31日各付息一次。宜蘭公司按有效利率法攤銷公司債溢折價。 試問該公司於X6年12月31日調整應認列之利息費用為多少？', '["$63,780", "$80,000", "$94,924", "$14,924"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01097', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '假設其他條件都不變的情況之下，下列何者為公司買回庫藏股時不會發生之情形？', '["權益總額減少", "現金總額減少", "公司流通在外股數減少", "每股盈餘變少"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01098', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '雲林公司X6年1月1日流通在外普通股200,000股，4月1日辦理現金減資，減少流通在外普通股20,000股， 5月1日買回普通股20,000股，8月1日對外發行普通股20,000股，並於12月1日出售庫藏股15,000股， 試計算雲林公司X6年度普通股加權平均流通在外股數：', '["181,250", "194,583", "176,250", "165,417"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01099', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '下列何者之會計處理可能影響保留盈餘之金額？①買入庫藏股  ②出售庫藏股  ③買入備供出售金融資產', '["出售備供出售金融資產", "僅", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01100', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司X1年初之應收帳款總額$1,800，備抵壞帳為貸餘$600，X1年底之應收帳款總額$2,100，備抵壞帳 為貸餘$400，X1年之壞帳損失為$100。在該公司以間接法編製之X1年現金流量表中，關於應收帳款項 目對淨利之調整數共計：', '["減少$500", "減少$400", "減少$300", "減少$200"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01101', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司X1年底以$200,000購入耐用年限10年之熔爐一座，熔爐裝有價值$4,000，按法規每4年即須汰 換並重置之防火內襯。甲公司對熔爐與防火內襯均以直線法提列折舊，估計無殘值，後續衡量採成本模 式。X3年底法規更改為每2年即須汰換並重置防火內襯，故該公司以$5,000汰換重置防火內襯。若此重 置支出符合資本支出之條件，則此重置對該公司X3年淨利之影響為（不考慮所得稅）：', '["無影響", "減少淨利$2,000", "減少淨利$5,000", "減少淨利$7,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01102', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '下列何者為應列報於綜合損益表之項目？①停業單位損益  ②會計原則變動累積影響數  ③財務成本', '["非常損益", "僅", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01103', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司於X1年初成立並發行面額$10之普通股80,000股及面額$100、股利率3%符合權益之累積特別股 10,000股，該公司之發行股數至X3年底並無變動且仍全數流通在外。若該公司X1年與X3年未宣告任 何股利，X4年始宣告發放現金股利$70,000，則該公司普通股股東可得之現金股利金額為：', '["$0", "$10,000", "$40,000", "$70,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01104', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '承上題，甲公司X3年底特別股積欠股利應認列之負債金額為：', '["$0", "$10,000", "$20,000", "$30,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01105', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司於X1年底發行100張面額$100,000之轉換公司債得款$10,200,000，每張公司債得於到期日前之任 何時間轉換為100股甲公司普通股。經評估該公司債所含之轉換權於當日之公允價值為$400,000，且若該 公司於當日發行相同條件但不可轉換之公司債將可得款$9,900,000。若假設無交易成本，則該公司債所含 之轉換權X1年底之帳面金額為：', '["$200,000", "$300,000", "$396,117", "$400,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01106', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '承上題，惟每張公司債得於到期日前之任何時間轉換為價值$100,000之甲公司普通股。若假設無交易成本， 且經評估甲公司須將該公司債中之主契約與轉換權分離，則該公司債所含之轉換權X1年底之帳面金額為：', '["$200,000", "$300,000", "$396,117", "$400,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01107', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司於X1 年底舉借五年期銀行借款$500,000，利率10%，約定自X2 年至X6 年間每年年底向銀行支付 $131,899即償付所有本息。關於該筆借款，甲公司於X2年底應認列之長期負債金額為（答案四捨五入至元）：', '["$500,000", "$418,101", "$328,012", "$228,914"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01108', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司於X1年底銷售一項資產並提供重要零件之保固，更換1個零件之成本為$1,000。經評估1個、2個、 3個零件故障須更換之機率分別為30%、50%、20%。關於該保固，甲公司於X1年底應認列之負債金額為：', '["$1,000", "$1,900", "$2,000", "$3,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01109', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '嘉義公司於X6年4月1日收到客戶開立6個月到期，面額為$500,000，利率為6%之票據一紙，該公司 於X6年8月1日將此票據持往銀行貼現，貼現率為8%。其貼現收入現金之金額為？', '["$508,133", "$504,700", "$509,850", "$512,425"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01110', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司X1年初之設備總額$27,000，累計折舊為$3,000，X1年底之設備總額$30,000，累計折舊為$5,000， X1年之設備折舊費用為$4,000，設備處分損失為$1,000。該公司X1年新購設備$7,000，且所有處分與購 置均發生於年底並以現金交割，則該公司X1年處分設備之現金流入為：', '["$1,000", "$2,000", "$3,000", "$4,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01111', 'bookkeeper', 'bookkeeper-moex-105-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '下列何者非為流動負債之條件？', '["企業能無條件遞延至報導期間後至少12個月以上方清償之負債", "企業預期於其正常營業週期中清償之負債", "企業預期於報導期間後12個月內到期清償之負債", "企業主要為交易目的而持有之負債"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "eb635094850d", "answer_pdf_sha1": "b571a9a07b87", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
